import{_ as e,a as i,b as o,c as a,d as p,e as l,f as n}from"./chunks/dvr.p8O1ibuT.js";import{_ as s}from"./chunks/multiconf.KueTB99t.js";import{c as g,Q as x,j as c,g as d,n as r,m as b}from"./chunks/framework.rlpw0eGz.js";const V=JSON.parse('{"title":"Інструкція з налаштування VRX Runcam WifiLink","description":"Покрокова інструкція налаштування VRX Runcam WifiLink підключення, WebUI, канали, DVR та моніторинг RSSI","frontmatter":{"title":"Інструкція з налаштування VRX Runcam WifiLink","description":"Покрокова інструкція налаштування VRX Runcam WifiLink підключення, WebUI, канали, DVR та моніторинг RSSI","head":[["link",{"rel":"canonical","href":"https://openfpv.com.ua/getting-started/groundstation"}],["link",{"rel":"alternate","hreflang":"uk","href":"https://openfpv.com.ua/getting-started/groundstation"}],["link",{"rel":"alternate","hreflang":"en","href":"https://openfpv.com.ua/en/getting-started/groundstation"}],["link",{"rel":"alternate","hreflang":"x-default","href":"https://openfpv.com.ua/getting-started/groundstation"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:url","content":"https://openfpv.com.ua/getting-started/groundstation"}],["meta",{"property":"og:title","content":"Інструкція з налаштування VRX Runcam WifiLink"}],["meta",{"property":"og:description","content":"Покрокова інструкція налаштування VRX Runcam WifiLink підключення, WebUI, канали, DVR та моніторинг RSSI"}],["meta",{"property":"og:image","content":"https://openfpv.com.ua/og-started.png"}],["meta",{"property":"og:locale","content":"uk_UA"}],["meta",{"property":"og:locale:alternate","content":"en_US"}],["meta",{"name":"twitter:image","content":"https://openfpv.com.ua/og-started.png"}],["meta",{"name":"twitter:title","content":"Інструкція з налаштування VRX Runcam WifiLink"}],["meta",{"name":"twitter:description","content":"Покрокова інструкція налаштування VRX Runcam WifiLink підключення, WebUI, канали, DVR та моніторинг RSSI"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@graph\\":[{\\"@type\\":\\"Organization\\",\\"@id\\":\\"https://openfpv.com.ua/#org\\",\\"name\\":\\"OpenFPV Ukraine\\",\\"url\\":\\"https://openfpv.com.ua\\",\\"logo\\":\\"https://openfpv.com.ua/logo-light.png\\",\\"sameAs\\":[\\"https://github.com/Maxwell456/openipc-docs-ukr\\"]},{\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"Головна\\",\\"item\\":\\"https://openfpv.com.ua/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Початок роботи\\",\\"item\\":\\"https://openfpv.com.ua/getting-started/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"Інструкція з налаштування VRX Runcam WifiLink\\"}]},{\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"Інструкція з налаштування VRX Runcam WifiLink\\",\\"description\\":\\"Покрокова інструкція налаштування VRX Runcam WifiLink підключення, WebUI, канали, DVR та моніторинг RSSI\\",\\"inLanguage\\":\\"uk-UA\\",\\"url\\":\\"https://openfpv.com.ua/getting-started/groundstation\\",\\"image\\":\\"https://openfpv.com.ua/og-started.png\\",\\"dateModified\\":\\"2026-05-31T08:38:19.000Z\\",\\"author\\":{\\"@id\\":\\"https://openfpv.com.ua/#org\\"},\\"publisher\\":{\\"@id\\":\\"https://openfpv.com.ua/#org\\"}}]}"]]},"headers":[],"relativePath":"getting-started/groundstation.md","filePath":"getting-started/groundstation.md","lastUpdated":1780216699000}'),m={name:"getting-started/groundstation.md"};function h(u,t,y,f,R,k){return x(),c("div",null,[...t[0]||(t[0]=[d("h1",{id:"інструкція-по-налаштуванню-vrx",tabindex:"-1"},[r("Інструкція по налаштуванню VRX "),d("a",{class:"header-anchor",href:"#інструкція-по-налаштуванню-vrx","aria-label":'Permalink to "Інструкція по налаштуванню VRX"'},"​")],-1),d("h2",{id:"runcam-wifilink-receiver",tabindex:"-1"},[r("Runcam WifiLink Receiver "),d("a",{class:"header-anchor",href:"#runcam-wifilink-receiver","aria-label":'Permalink to "Runcam WifiLink Receiver"'},"​")],-1),d("div",{style:{"text-align":"center"}},[d("iframe",{width:"560",height:"315",src:"https://www.youtube.com/embed/BP7Ns7H9wvI?si=sUkZiTPDYfQbjkLS",title:"YouTube video player",frameborder:"0",allow:"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share",referrerpolicy:"strict-origin-when-cross-origin",allowfullscreen:""})],-1),b('<div class="warning custom-block"><p class="custom-block-title">Увага</p><p>Не підключайте живлення до VRx, якщо HDMI-кабель під’єднаний, а джерело HDMI вимкнене — це може пошкодити HDMI-вихід!</p></div><ol><li>Підключіть живлення <strong>DC 9–30V</strong> та кабель <strong>miniHDMI-to-HDMI</strong> до окулярів або шолома.</li><li>За допомогою <strong>HID-джойстика</strong> можна налаштувати канал зв’язку (за замовчуванням <code>161 → 5.8 GHz</code>).</li><li>Підключіть живлення до дрона та відеоприймача (VRX). За замовчуванням і дрон, і VRX налаштовані на канал <code>161</code> та роздільну здатність <code>1920×1080</code> — зображення зʼявиться протягом <strong>10 секунд</strong>.</li></ol><br><p>💡 <em><strong>На цьому все! Можна літати на цифрі від OpenIPC.</strong></em></p><hr><h2 id="додаткові-налаштування-vrx-runcam" tabindex="-1">Додаткові налаштування VRX Runcam <a class="header-anchor" href="#додаткові-налаштування-vrx-runcam" aria-label="Permalink to &quot;Додаткові налаштування VRX Runcam&quot;">​</a></h2><h3 id="_1-вхід-у-webui" tabindex="-1">1. Вхід у WebUI <a class="header-anchor" href="#_1-вхід-у-webui" aria-label="Permalink to &quot;1. Вхід у WebUI&quot;">​</a></h3><p>Щоб змінити роздільну здатність VRX (FullHD або HD), необхідно увійти в режим <strong>AP Mode (Wi-Fi точка доступу)</strong>:<br> утримуйте джойстик на VRX до появи надпису <strong>&quot;AP mode ON&quot;</strong> на екрані.</p><p>📶 Зʼявиться Wi-Fi мережа: <code>RadxaGroundStation</code><br> 🔑 Пароль: <code>radxaopenipc</code></p><p>Після підключення перейдіть у браузері за адресою:</p><p><a href="http://radxa-zero3.local/" target="_blank" rel="noreferrer">http://radxa-zero3.local/</a></p><blockquote><p>У WebUI ви зможете:<br> • змінити канали зв’язку<br> • завантажити або переглянути DVR<br> • налаштувати Adaptive Link<br> • обрати роздільну здатність<br> • переглянути графік RSSI</p></blockquote><hr><h3 id="_2-основні-функціі-webui" tabindex="-1">2. Основні функції WebUI <a class="header-anchor" href="#_2-основні-функціі-webui" aria-label="Permalink to &quot;2. Основні функції WebUI&quot;">​</a></h3><img src="'+e+'" alt="alink" width="1000px"><ul><li><strong>DVR</strong></li><li><strong>Налаштування VRX</strong></li><li><strong>Налаштування камери</strong></li><li><strong>RSSI графік</strong> <em>(працює, коли є зʼєднання між VRX та Air Unit)</em></li></ul><hr><h3 id="_3-налаштування-роздільноі-здатності" tabindex="-1">3. Налаштування роздільної здатності <a class="header-anchor" href="#_3-налаштування-роздільноі-здатності" aria-label="Permalink to &quot;3. Налаштування роздільної здатності&quot;">​</a></h3><p>Перейдіть до <strong>Groundstation Editor → Screen-mode → Edit</strong><br> Встановіть роздільну здатність, наприклад: <code>1280×720</code> — вона має <strong>збігатися з налаштуваннями Air Unit</strong>.</p><img src="'+i+'" alt="alink" width="1000px"><hr><h3 id="_4-налаштування-каналу-зв-язку" tabindex="-1">4. Налаштування каналу зв’язку <a class="header-anchor" href="#_4-налаштування-каналу-зв-язку" aria-label="Permalink to &quot;4. Налаштування каналу зв’язку&quot;">​</a></h3><p>Перейдіть до <strong>Groundstation Editor → wifibroadcast.cfg → Edit</strong><br> Встановіть інший канал зв’язку на вибір (наприклад: <code>140</code>, <code>64</code>, тощо) —<br><strong>він має збігатися з каналом на Air Unit</strong>.</p><img src="'+o+'" alt="alink" width="1000px"><h4 id="📡-таблиця-каналів-зв-язку-5-8-ghz-20-mhz" tabindex="-1">📡 Таблиця каналів зв’язку 5.8 GHz (20 MHz) <a class="header-anchor" href="#📡-таблиця-каналів-зв-язку-5-8-ghz-20-mhz" aria-label="Permalink to &quot;📡 Таблиця каналів зв’язку 5.8 GHz (20 MHz)&quot;">​</a></h4><table style="width:100%;border-collapse:collapse;margin:15px 0;"><thead><tr><th style="padding:10px;border:1px solid #ddd;text-align:left;">№ каналу</th><th style="padding:10px;border:1px solid #ddd;text-align:left;">Частота (MHz)</th><th style="padding:10px;border:1px solid #ddd;text-align:left;">Примітка</th></tr></thead><tbody><tr><td style="padding:8px;border:1px solid #ddd;">36</td><td style="padding:8px;border:1px solid #ddd;">5180</td><td style="padding:8px;border:1px solid #ddd;">Wi-Fi</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">40</td><td style="padding:8px;border:1px solid #ddd;">5200</td><td style="padding:8px;border:1px solid #ddd;">Wi-Fi</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">44</td><td style="padding:8px;border:1px solid #ddd;">5220</td><td style="padding:8px;border:1px solid #ddd;">Wi-Fi</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">48</td><td style="padding:8px;border:1px solid #ddd;">5240</td><td style="padding:8px;border:1px solid #ddd;">Wi-Fi</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">52</td><td style="padding:8px;border:1px solid #ddd;">5260</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">56</td><td style="padding:8px;border:1px solid #ddd;">5280</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">60</td><td style="padding:8px;border:1px solid #ddd;">5300</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">64</td><td style="padding:8px;border:1px solid #ddd;">5320</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">100</td><td style="padding:8px;border:1px solid #ddd;">5500</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">104</td><td style="padding:8px;border:1px solid #ddd;">5520</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">108</td><td style="padding:8px;border:1px solid #ddd;">5540</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">112</td><td style="padding:8px;border:1px solid #ddd;">5560</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">116</td><td style="padding:8px;border:1px solid #ddd;">5580</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">120</td><td style="padding:8px;border:1px solid #ddd;">5600</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">124</td><td style="padding:8px;border:1px solid #ddd;">5620</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">128</td><td style="padding:8px;border:1px solid #ddd;">5640</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">132</td><td style="padding:8px;border:1px solid #ddd;">5660</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">136</td><td style="padding:8px;border:1px solid #ddd;">5680</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">140</td><td style="padding:8px;border:1px solid #ddd;">5700</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">144</td><td style="padding:8px;border:1px solid #ddd;">5720</td><td style="padding:8px;border:1px solid #ddd;">DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">149</td><td style="padding:8px;border:1px solid #ddd;">5745</td><td style="padding:8px;border:1px solid #ddd;">Без DFS (зазвичай дозволено)</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">153</td><td style="padding:8px;border:1px solid #ddd;">5765</td><td style="padding:8px;border:1px solid #ddd;">Без DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">157</td><td style="padding:8px;border:1px solid #ddd;">5785</td><td style="padding:8px;border:1px solid #ddd;">Без DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">161</td><td style="padding:8px;border:1px solid #ddd;">5805</td><td style="padding:8px;border:1px solid #ddd;">Найпопулярніший</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">165</td><td style="padding:8px;border:1px solid #ddd;">5825</td><td style="padding:8px;border:1px solid #ddd;">Без DFS</td></tr><tr><td style="padding:8px;border:1px solid #ddd;">169</td><td style="padding:8px;border:1px solid #ddd;">5845</td><td style="padding:8px;border:1px solid #ddd;"><em>Нестандартний</em></td></tr><tr><td style="padding:8px;border:1px solid #ddd;">173</td><td style="padding:8px;border:1px solid #ddd;">5865</td><td style="padding:8px;border:1px solid #ddd;"><em>Нестандартний</em></td></tr><tr><td style="padding:8px;border:1px solid #ddd;">177</td><td style="padding:8px;border:1px solid #ddd;">5885</td><td style="padding:8px;border:1px solid #ddd;"><em>Нестандартний</em></td></tr></tbody></table><blockquote><p><strong>❗ Що таке DFS (Dynamic Frequency Selection):</strong><br> Це технологія, яка дозволяє Wi-Fi або FPV-пристроям працювати на частотах, що можуть перетинатися з військовими чи метеорологічними радарами.<br> Якщо пристрій виявляє активність радара — він автоматично змінює канал.</p></blockquote><hr><h3 id="_5-налаштування-камери-air-unit" tabindex="-1">5. Налаштування камери (Air Unit) <a class="header-anchor" href="#_5-налаштування-камери-air-unit" aria-label="Permalink to &quot;5. Налаштування камери (Air Unit)&quot;">​</a></h3><p>Перейдіть до:<br><strong>Camera Settings → Load Current Config</strong></p><ul><li>Зачекайте, поки завантажаться параметри з камери</li><li>Внесіть зміни</li><li>Збережіть</li><li>Виконайте перезавантаження <strong>Majestic</strong></li></ul><img src="'+a+'" alt="alink" width="1000px"><img src="'+p+'" alt="alink" width="1000px"><hr><h3 id="_6-rssi-графік" tabindex="-1">6. RSSI графік <a class="header-anchor" href="#_6-rssi-графік" aria-label="Permalink to &quot;6. RSSI графік&quot;">​</a></h3><p>Графік <strong>RSSI</strong> дозволяє в реальному часі оцінити силу сигналу, якість зв’язку, а також перевірити ефективність розміщення антен і стабільність лінку.</p><img src="'+l+'" alt="alink" width="1000px"><h3 id="_7-dvr" tabindex="-1">7. DVR <a class="header-anchor" href="#_7-dvr" aria-label="Permalink to &quot;7. DVR&quot;">​</a></h3><p>Скачати або видалити запис вашого польоту</p><img src="'+n+'" alt="alink" width="1000px"><h3 id="_8-підключення-radxa-до-домашньоі-мережі" tabindex="-1">8. Підключення Radxa до домашньої мережі <a class="header-anchor" href="#_8-підключення-radxa-до-домашньоі-мережі" aria-label="Permalink to &quot;8. Підключення Radxa до домашньої мережі&quot;">​</a></h3><p><strong>Необхідні програми</strong></p><ol><li>Win32 Disk Imager</li><li>SD Memory Card Formatter</li><li>PuTTY (SSH)</li><li>WinSCP (FTP)</li></ol><p><strong>Початкове налаштування Radxa</strong></p><ol><li>Запишіть образ Radxa (версія 1.9.9) на microSD через Win32 Disk Imager.</li><li>Вставте карту, підключіть клавіатуру, монітор, вимкніть живлення Wi‑Fi карт(⚠️обов&#39;язково).</li><li>Увімкніть, зайдіть через SSH (root/root).</li><li><code>nmtui</code> → підключіться до домашнього Wi‑Fi → перезавантажте.</li><li>(Опційно) AP‑режим → radxa-zero3.local → Web UI.</li></ol><p><img src="'+s+'" alt="alink" width="800px"><br><strong>Налаштування камери (Runcam WiFiLink v1/v2)</strong></p><ol><li>Підключіть мережевий кабель до роутера або ПК (IP 192.168.1.10).</li><li>Відкрийте OpenIPC Configurator → Connect → виберіть камеру.</li><li><strong>Camera</strong>: - Роздільна здатність (1920×1080 або 1280×720) -&gt; Бітрейт (наприклад 12 228 kbps; з Alink – авто)</li><li><strong>Telemetry</strong>: увімкнути UART0 + Mavlink → рестарт</li><li><strong>Firmware</strong>: оновлення прошивки → Update</li><li><strong>Advanced</strong>: увімкнути Alink → перегляд логів</li></ol>',47)])])}const v=g(m,[["render",h]]);export{V as __pageData,v as default};
